  answerAuthorName: string;
  answerAuthorRoleId: string | null;
  answerAuthorIsAnonymous: boolean;
  existingComments: Array<{ id: string; authorName: string; content: string }>;
  /** mode=comment 鏃剁帺瀹跺垰鍙戣瘎璁虹殑 id锛屽彲浣滀负 parentCommentId */
