const isChineseChar = (ch: string) => /^[\u4e00-\u9fa5]$/.test(ch);

const extractSurnameAndGivenChars = (fullName: string): { surname: string | null; givenChars: string[] } => {
  const pure = (fullName || '').trim().replace(/\s+/g, '');
  const chars = Array.from(pure).filter(isChineseChar);
  if (chars.length < 2) return { surname: null, givenChars: [] };
  return {
    surname: chars[0] || null,
    givenChars: chars.slice(1)
  };
};

const buildExtraNamePoolsFromIdentities = (
  identities: Array<{ name?: string; gender?: 'male' | 'female' | 'other' | '' }>
): { surnames: string[]; maleGiven: string[]; femaleGiven: string[] } => {
  const surnameSet = new Set<string>();
  const maleGivenSet = new Set<string>();
  const femaleGivenSet = new Set<string>();

  identities.forEach((id) => {
    const parsed = extractSurnameAndGivenChars(id.name || '');
    if (parsed.surname) surnameSet.add(parsed.surname);
    parsed.givenChars.forEach((ch) => {
      if (id.gender === 'male') {
        maleGivenSet.add(ch);
      } else if (id.gender === 'female') {
        femaleGivenSet.add(ch);
      } else {
        maleGivenSet.add(ch);
        femaleGivenSet.add(ch);
      }
    });
  });

  return {
    surnames: Array.from(surnameSet),
    maleGiven: Array.from(maleGivenSet),
    femaleGiven: Array.from(femaleGivenSet)
  };
};

const generateRomanceNameByGender = (
  gender: 'male' | 'female' | 'other' | '' = '',
  identities: Array<{ name?: string; gender?: 'male' | 'female' | 'other' | '' }> = []
): string => {
  const extra = buildExtraNamePoolsFromIdentities(identities);
  const surnamesPool = Array.from(new Set([...ROMANCE_SURNAMES, ...extra.surnames]));
  const surname = surnamesPool[Math.floor(Math.random() * surnamesPool.length)];

  let pool: string[] = [];
  if (gender === 'male') {
    pool = Array.from(new Set([...ROMANCE_GIVEN_MALE, ...extra.maleGiven]));
  } else if (gender === 'female') {
    pool = Array.from(new Set([...ROMANCE_GIVEN_FEMALE, ...extra.femaleGiven]));
  } else {
    pool = Array.from(new Set([...ROMANCE_GIVEN_MALE, ...ROMANCE_GIVEN_FEMALE, ...extra.maleGiven, ...extra.femaleGiven]));
  }

  // 濮?+ 1~2 涓悕锛氭€婚暱搴﹀浐瀹?2~3 涓瓧
  const givenLen = Math.random() < 0.5 ? 1 : 2;
  let given = '';
  for (let i = 0; i < givenLen; i += 1) {
    given += pool[Math.floor(Math.random() * pool.length)];
  }
  return surname + given;
};

