const DEFAULT_PROACTIVE_MESSAGE_INTERVAL_MINUTES = 60;

const clampProactiveMessageIntervalMinutes = (n: number | undefined): number => {
  const x =
    typeof n === 'number' && Number.isFinite(n)
      ? Math.round(n)
      : DEFAULT_PROACTIVE_MESSAGE_INTERVAL_MINUTES;
  return Math.max(5, Math.min(24 * 60, x));
};

