const loadWeChatBusyMaxMinutes = (): number => {
  try {
    const raw = appStorage.getItem(WECHAT_BUSY_MAX_MINUTES_KEY);
    if (!raw) return 10;
    const n = Number(raw);
    if (!Number.isFinite(n)) return 10;
    const v = Math.round(n);
    if (v < 1) return 1;
    if (v > 60) return 60;
    return v;
  } catch {
    return 10;
  }
};

const saveWeChatBusyMaxMinutes = (minutes: number) => {
  try {
    const v = Math.round(minutes);
    const safe = Math.max(1, Math.min(60, Number.isFinite(v) ? v : 10));
    appStorage.setItem(WECHAT_BUSY_MAX_MINUTES_KEY, String(safe));
  } catch {
    // ignore
  }
};

