const loadWeChatDanmakuSettings = (): WeChatDanmakuSettings => {
  const fallback: WeChatDanmakuSettings = {
    enabled: true,
    stylePreset: 'balanced',
    customStyleText: '',
    perRoundCount: 8,
    apiMode: 'default',
    customApiBaseUrl: '',
    customApiKey: '',
    customApiModel: '',
    viewportHeightRatio: 0.25
  };
  try {
    const raw = appStorage.getItem(WECHAT_DANMAKU_SETTINGS_KEY);
    if (!raw) return fallback;
    const parsed = JSON.parse(raw) as Partial<WeChatDanmakuSettings>;

    const perRoundCount =
      typeof parsed.perRoundCount === 'number' && parsed.perRoundCount > 0
        ? Math.max(1, Math.min(20, Math.round(parsed.perRoundCount)))
        : fallback.perRoundCount;

    const viewportHeightRatioRaw =
      typeof parsed.viewportHeightRatio === 'number'
        ? parsed.viewportHeightRatio
        : fallback.viewportHeightRatio;
    const viewportHeightRatio = Math.max(
      0.25,
      Math.min(1, viewportHeightRatioRaw || fallback.viewportHeightRatio)
    );

    const allowedPresets: Array<WeChatDanmakuStylePreset | 'custom'> = [
      'balanced',
      'warm',
      'lively',
      'crazy',
      'cool',
      'custom'
    ];
    const stylePreset = allowedPresets.includes(
      (parsed.stylePreset || fallback.stylePreset) as WeChatDanmakuStylePreset | 'custom'
    )
      ? ((parsed.stylePreset ||
        fallback.stylePreset) as WeChatDanmakuStylePreset | 'custom')
      : 'balanced';

    const apiMode: 'default' | 'custom' =
      parsed.apiMode === 'custom' ? 'custom' : 'default';

    return {
      ...fallback,
      ...parsed,
      enabled: parsed.enabled ?? fallback.enabled,
      stylePreset,
      perRoundCount,
      apiMode,
      viewportHeightRatio,
      customStyleText: parsed.customStyleText ?? '',
      customApiBaseUrl: parsed.customApiBaseUrl ?? '',
      customApiKey: parsed.customApiKey ?? '',
      customApiModel: parsed.customApiModel ?? ''
    };
  } catch {
    return fallback;
  }
};

const saveWeChatDanmakuSettings = (settings: WeChatDanmakuSettings) => {
  try {
    const perRoundCount = Math.max(
      1,
      Math.min(20, Math.round(settings.perRoundCount || 8))
    );
    const viewportHeightRatio = Math.max(
      0.25,
      Math.min(1, settings.viewportHeightRatio || 0.25)
    );
    const allowedPresets: WeChatDanmakuStylePreset[] = [
      'balanced',
      'warm',
      'lively',
      'crazy',
      'cool'
    ];
    const rawPreset = settings.stylePreset;
    const stylePreset: WeChatDanmakuStylePreset | 'custom' =
      rawPreset === 'custom' || allowedPresets.includes(rawPreset as WeChatDanmakuStylePreset)
        ? rawPreset
        : 'balanced';
    const apiMode: 'default' | 'custom' =
      settings.apiMode === 'custom' ? 'custom' : 'default';

    const safe: WeChatDanmakuSettings = {
      enabled: !!settings.enabled,
      stylePreset,
      customStyleText: settings.customStyleText || '',
      perRoundCount,
      apiMode,
      customApiBaseUrl: settings.customApiBaseUrl || '',
      customApiKey: settings.customApiKey || '',
      customApiModel: settings.customApiModel || '',
      viewportHeightRatio
    };

    appStorage.setItem(WECHAT_DANMAKU_SETTINGS_KEY, JSON.stringify(safe));
  } catch {
    // ignore
  }
};

