const loadPlayerIdentity = (): PlayerIdentity => {
  // 浼樺厛璇诲彇绾夸笅鏁呬簨涓殑鐜╁韬唤
  try {
    const raw = appStorage.getItem(STORY_IDENTITY_KEY);
    if (raw) {
      const parsed = JSON.parse(raw) as Partial<PlayerIdentity>;
      const name = (parsed as any).name ?? (parsed as any).nickname ?? '';
      return {
        name: name ?? '',
        alias: parsed.alias ?? undefined,
        gender: parsed.gender ?? '',
        intro: parsed.intro ?? '',
        tags: parsed.tags ?? '',
        worldbooks: (parsed as any).worldbooks ?? [],
        phoneNumber: (parsed as any).phoneNumber ?? undefined,
        wechatId: (parsed as any).wechatId ?? undefined,
        wechatNickname: (parsed as any).wechatNickname ?? name ?? ''
      };
    }
  } catch {
    // ignore and fallback
  }

  // 鍏煎鏃х増鏈殑寰俊渚х帺瀹惰韩浠?
  try {
    const raw = appStorage.getItem(LEGACY_IDENTITY_KEY);
    if (raw) {
      const parsed = JSON.parse(raw) as Partial<PlayerIdentity>;
      const name = parsed.name ?? '';
      return {
        name,
        alias: parsed.alias ?? undefined,
        gender: '',
        intro: '',
        tags: '',
        worldbooks: [],
        phoneNumber: undefined,
        wechatId: undefined,
        wechatNickname: parsed.wechatNickname ?? name
      };
    }
  } catch {
    // ignore
  }

  return {
    name: '',
    alias: undefined,
    gender: '',
    intro: '',
    tags: '',
    worldbooks: [],
    phoneNumber: undefined,
    wechatId: undefined,
    wechatNickname: ''
  };
};

