const generateWalletId = (): string => {
  return `wallet_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`;
};

// 绾㈠寘鍏ヨ处鍒伴挶鍖?
const addRedPacketToWallet = (amount: number): boolean => {
  try {
    const wallet = loadWeChatWallet();
    if (!wallet) {
      // 濡傛灉閽卞寘涓嶅瓨鍦紝鍏堝垱寤轰竴涓粯璁ら挶鍖?
      const newWallet: WeChatWallet = {
        walletId: generateWalletId(),
        balance: amount,
        paymentPassword: '000000', // 榛樿瀵嗙爜锛岀敤鎴峰悗缁彲浠ヤ慨鏀?
        createdAt: Date.now()
      };
      saveWeChatWallet(newWallet);
      return true;
    }
    
    // 鏇存柊閽卞寘浣欓
    const updatedWallet: WeChatWallet = {
      ...wallet,
      balance: wallet.balance + amount
    };
    saveWeChatWallet(updatedWallet);
    return true;
  } catch {
    return false;
  }
};

