  // 鏍煎紡鍖栭€氳瘽鏃堕暱锛氬皢绉掓暟杞崲涓?MM:SS 鎴?HH:MM:SS 鏍煎紡
  const formatCallDuration = React.useCallback((seconds: number): string => {
    const hours = Math.floor(seconds / 3600);
    const minutes = Math.floor((seconds % 3600) / 60);
    const secs = seconds % 60;
    
    if (hours > 0) {
      return `${hours.toString().padStart(2, '0')}:${minutes.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
    }
    return `${minutes.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  }, []);

  // 璇煶閫氳瘽锛氬綋閫氳瘽鎺ラ€氭椂锛屽紑濮嬭鏃?
  React.useEffect(() => {
    if (voiceCallPhase === 'connected' && !voiceCallStartTime) {
      const startTime = Date.now();
      setVoiceCallStartTime(startTime);
      setVoiceCallDuration(0);
    } else if (voiceCallPhase !== 'connected') {
      // 閫氳瘽缁撴潫锛岄噸缃鏃跺櫒
      setVoiceCallStartTime(null);
      setVoiceCallDuration(0);
    }
  }, [voiceCallPhase, voiceCallStartTime]);

