  React.useEffect(() => {
    if (voiceCallPhase === 'connected' && voiceCallStartTime) {
      const interval = setInterval(() => {
        const elapsed = Math.floor((Date.now() - voiceCallStartTime) / 1000);
        setVoiceCallDuration(elapsed);
      }, 1000);
      return () => clearInterval(interval);
    }
  }, [voiceCallPhase, voiceCallStartTime]);

