  const truncateHeaderTitle = (s: string, maxChars: number) => {
    const raw = String(s || '').trim();
    if (!raw) return raw;
    if (maxChars <= 0) return '...';
    return raw.length > maxChars ? `${raw.slice(0, maxChars)}...` : raw;
  };

  // 缇よ亰鏍囬锛氬彧鐪佺暐缇ゅ悕绉帮紝鏈熬鎷彿鍐呬汉鏁颁繚鐣欙紙渚嬪 "缇ゅ悕锛?2锛? / "缇ゅ悕(12)"锛?
  const truncateGroupHeaderTitleKeepCount = (title: string, maxNameChars: number) => {
    const raw = String(title || '').trim();
    if (!raw) return raw;
    const match = raw.match(/^(.*?)([锛?][^锛?]*[锛?])\s*$/u);
    const namePart = (match?.[1] ?? raw).trim();
    const suffix = match?.[2] ?? '';
    const safeName = namePart || '缇よ亰';
    const truncatedName = truncateHeaderTitle(safeName, maxNameChars);
    return `${truncatedName}${suffix}`;
  };

