                                        if (idx < 0) return;
                                        const group = groups[idx];
                                        const members = Array.isArray((group as any)?.members)
                                          ? (((group as any).members as any[]) || [])
                                          : [];
                                        const mi = members.findIndex((mm) => normalizeGroupRoleId(mm?.roleId) === normalizedRid);
